import{_ as t,o as i,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"56. Time Limit On Higher Duties","description":"","frontmatter":{"title":"56. Time Limit On Higher Duties","eba":"Mental Health Services 2024-2028","topics":["disputes","staffing"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/staffing/56-time-limit-on-higher-duties.md","filePath":"ebas/mental-health/common-terms/staffing/56-time-limit-on-higher-duties.md"}'),o={name:"ebas/mental-health/common-terms/staffing/56-time-limit-on-higher-duties.md"};function s(r,e,m,h,l,c){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="_56-time-limit-on-higher-duties" tabindex="-1">56. Time Limit On Higher Duties <a class="header-anchor" href="#_56-time-limit-on-higher-duties" aria-label="Permalink to &quot;56. Time Limit On Higher Duties&quot;">​</a></h1><p><strong>56.1</strong> Where following vacancy advertisement as per <a href="/eba/ebas/mental-health/common-terms/staffing/55-recruitment-to-vacant-position.html">clause 55</a>, an Employee has been performing higher duties due to a vacancy for a continuous period of 9 months, the employee will be permanently appointed to the role unless the employee requests otherwise in writing.</p><p><strong>56.2</strong> This provision will not apply where the role is subject to a notified change process as per <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/23-alternative-dispute-resolution-procedure.html">clause 23</a> and the Dispute Resolution Procedure. Any period between the notification of the change and the implementation of that change will not count for the purpose of 56.1.</p><p>Plain language terms: acting up, higher duties allowance, HDA.</p>',4)])])}const d=t(o,[["render",s]]);export{u as __pageData,d as default};
